import { DraftPoolResponse } from "@/lib/dto";
import { env } from "@/lib/env";

// NOTE: awaiting NSwag regen — DraftPartDetail will be generated by NSwag
export interface DraftPartDetail {
  publicId: string;
  partNumber: number;
  draftId: string;
  draftName: string;
  draftType: { name: string; value: number };
  status: { name: string; value: number };
  positions: DraftPartPosition[];
  participants: DraftPartParticipantInfo[];
}

export interface DraftPartPosition {
  name: string;
  participantName?: string;
  picks: DraftPartPick[];
}

export interface DraftPartPick {
  tmdbId?: number;
  title?: string;
  year?: number;
  posterUrl?: string;
  pickType?: string;
}

export interface DraftPartParticipantInfo {
  name: string;
  remainingVetoes: number;
  remainingOverrides: number;
}

const apiBase = env.apiUrl;

export async function getDraftPart(
  accessToken: string | undefined,
  draftPartId: string
): Promise<DraftPartDetail | null> {
  // TODO: confirm response shape — DraftPartDetail will be generated by NSwag
  try {
    const res = await fetch(
      `${apiBase}/draft-parts/${encodeURIComponent(draftPartId)}`,
      {
        headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
        cache: "no-store",
      }
    );
    if (!res.ok) return null;
    return (await res.json()) as DraftPartDetail;
  } catch (err) {
    console.error("[getDraftPart]", err);
    return null;
  }
}

export async function getDraftPool(
  accessToken: string | undefined,
  draftId: string
): Promise<DraftPoolResponse | null> {
  try {
    const res = await fetch(
      `${apiBase}/drafts/${encodeURIComponent(draftId)}/pool`,
      {
        headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
        cache: "no-store",
      }
    );
    if (res.status === 404) return null;
    if (!res.ok) return null;
    return (await res.json()) as DraftPoolResponse;
  } catch (err) {
    console.error("[getDraftPool]", err);
    return null;
  }
}
